import React, { useState } from 'react';
import './AppointmentBooking.css';

const AppointmentBooking = ({ isOpen, onClose }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    condition: '',
    preferredDate: '',
    preferredTime: '',
    treatmentType: '',
    message: '',
    consultationType: 'in-person'
  });
  const [currentStep, setCurrentStep] = useState(1);
  const [isSubmitted, setIsSubmitted] = useState(false);

  const treatmentTypes = [
    'General Consultation',
    'Herbal Medicine Consultation',
    'Nutritional Therapy',
    'Pain Management',
    'Stress & Anxiety Treatment',
    'Digestive Health',
    'Immune System Support',
    'Sleep Disorders',
    'Skin Conditions',
    'Chronic Disease Management'
  ];

  const conditions = [
    'Arthritis',
    'High Blood Pressure',
    'Diabetes',
    'Digestive Issues',
    'Insomnia',
    'Anxiety/Depression',
    'Skin Problems',
    'Chronic Pain',
    'Immune Deficiency',
    'Heart Disease',
    'Liver Problems',
    'Other'
  ];

  const timeSlots = [
    '08:00 AM', '09:00 AM', '10:00 AM', '11:00 AM',
    '02:00 PM', '03:00 PM', '04:00 PM', '05:00 PM'
  ];

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleNext = () => {
    if (currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrevious = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // In a real app, this would make an API call
    console.log('Appointment booking:', formData);
    setIsSubmitted(true);
  };

  const resetForm = () => {
    setFormData({
      name: '',
      email: '',
      phone: '',
      condition: '',
      preferredDate: '',
      preferredTime: '',
      treatmentType: '',
      message: '',
      consultationType: 'in-person'
    });
    setCurrentStep(1);
    setIsSubmitted(false);
  };

  const handleClose = () => {
    resetForm();
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="appointment-modal-overlay" onClick={handleClose}>
      <div className="appointment-modal" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2 className="modal-title">Book Your Natural Healing Consultation</h2>
          <button className="modal-close" onClick={handleClose}>×</button>
        </div>

        {isSubmitted ? (
          <div className="success-content">
            <div className="success-icon">✓</div>
            <h3>Appointment Request Submitted!</h3>
            <p>Thank you for choosing Gems of Insight for your natural healing journey.</p>
            <div className="appointment-summary">
              <h4>Appointment Details:</h4>
              <div className="summary-item">
                <strong>Name:</strong> {formData.name}
              </div>
              <div className="summary-item">
                <strong>Treatment:</strong> {formData.treatmentType}
              </div>
              <div className="summary-item">
                <strong>Date:</strong> {formData.preferredDate}
              </div>
              <div className="summary-item">
                <strong>Time:</strong> {formData.preferredTime}
              </div>
              <div className="summary-item">
                <strong>Type:</strong> {formData.consultationType === 'in-person' ? 'In-Person' : 'Virtual'}
              </div>
            </div>
            <p className="confirmation-note">
              We'll contact you within 24 hours to confirm your appointment and provide further details.
            </p>
            <button className="confirm-btn" onClick={handleClose}>Close</button>
          </div>
        ) : (
          <>
            <div className="progress-bar">
              <div className="progress-steps">
                {[1, 2, 3].map(step => (
                  <div 
                    key={step} 
                    className={`progress-step ${currentStep >= step ? 'active' : ''}`}
                  >
                    {step}
                  </div>
                ))}
              </div>
              <div className="progress-labels">
                <span className={currentStep >= 1 ? 'active' : ''}>Personal Info</span>
                <span className={currentStep >= 2 ? 'active' : ''}>Treatment Details</span>
                <span className={currentStep >= 3 ? 'active' : ''}>Schedule</span>
              </div>
            </div>

            <form onSubmit={handleSubmit} className="appointment-form">
              {currentStep === 1 && (
                <div className="form-step">
                  <h3>Personal Information</h3>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Full Name *</label>
                      <input
                        type="text"
                        name="name"
                        value={formData.name}
                        onChange={handleInputChange}
                        required
                        placeholder="Enter your full name"
                      />
                    </div>
                    <div className="form-group">
                      <label>Email Address *</label>
                      <input
                        type="email"
                        name="email"
                        value={formData.email}
                        onChange={handleInputChange}
                        required
                        placeholder="your.email@example.com"
                      />
                    </div>
                  </div>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Phone Number *</label>
                      <input
                        type="tel"
                        name="phone"
                        value={formData.phone}
                        onChange={handleInputChange}
                        required
                        placeholder="+254 7XX XXX XXX"
                      />
                    </div>
                    <div className="form-group">
                      <label>Primary Health Condition</label>
                      <select
                        name="condition"
                        value={formData.condition}
                        onChange={handleInputChange}
                      >
                        <option value="">Select condition</option>
                        {conditions.map(condition => (
                          <option key={condition} value={condition}>{condition}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                </div>
              )}

              {currentStep === 2 && (
                <div className="form-step">
                  <h3>Treatment Details</h3>
                  <div className="form-group">
                    <label>Type of Treatment *</label>
                    <select
                      name="treatmentType"
                      value={formData.treatmentType}
                      onChange={handleInputChange}
                      required
                    >
                      <option value="">Select treatment type</option>
                      {treatmentTypes.map(type => (
                        <option key={type} value={type}>{type}</option>
                      ))}
                    </select>
                  </div>

                  <div className="form-group">
                    <label>Consultation Type *</label>
                    <div className="radio-group">
                      <label className="radio-label">
                        <input
                          type="radio"
                          name="consultationType"
                          value="in-person"
                          checked={formData.consultationType === 'in-person'}
                          onChange={handleInputChange}
                        />
                        <span className="radio-custom"></span>
                        In-Person Consultation (KSH 3,000)
                      </label>
                      <label className="radio-label">
                        <input
                          type="radio"
                          name="consultationType"
                          value="virtual"
                          checked={formData.consultationType === 'virtual'}
                          onChange={handleInputChange}
                        />
                        <span className="radio-custom"></span>
                        Virtual Consultation (KSH 2,000)
                      </label>
                    </div>
                  </div>

                  <div className="form-group">
                    <label>Additional Information</label>
                    <textarea
                      name="message"
                      value={formData.message}
                      onChange={handleInputChange}
                      placeholder="Please describe your symptoms, current medications, or any specific concerns..."
                      rows="4"
                    ></textarea>
                  </div>
                </div>
              )}

              {currentStep === 3 && (
                <div className="form-step">
                  <h3>Schedule Your Appointment</h3>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Preferred Date *</label>
                      <input
                        type="date"
                        name="preferredDate"
                        value={formData.preferredDate}
                        onChange={handleInputChange}
                        required
                        min={new Date().toISOString().split('T')[0]}
                      />
                    </div>
                    <div className="form-group">
                      <label>Preferred Time *</label>
                      <select
                        name="preferredTime"
                        value={formData.preferredTime}
                        onChange={handleInputChange}
                        required
                      >
                        <option value="">Select time</option>
                        {timeSlots.map(time => (
                          <option key={time} value={time}>{time}</option>
                        ))}
                      </select>
                    </div>
                  </div>

                  <div className="appointment-summary-preview">
                    <h4>Appointment Summary</h4>
                    <div className="summary-grid">
                      <div><strong>Treatment:</strong> {formData.treatmentType}</div>
                      <div><strong>Type:</strong> {formData.consultationType === 'in-person' ? 'In-Person' : 'Virtual'}</div>
                      <div><strong>Fee:</strong> KSH {formData.consultationType === 'in-person' ? '3,000' : '2,000'}</div>
                      <div><strong>Date:</strong> {formData.preferredDate}</div>
                      <div><strong>Time:</strong> {formData.preferredTime}</div>
                    </div>
                  </div>
                </div>
              )}

              <div className="form-actions">
                {currentStep > 1 && (
                  <button type="button" onClick={handlePrevious} className="btn-secondary">
                    Previous
                  </button>
                )}
                {currentStep < 3 ? (
                  <button type="button" onClick={handleNext} className="btn-primary">
                    Continue
                  </button>
                ) : (
                  <button type="submit" className="btn-primary">
                    Book Appointment
                  </button>
                )}
              </div>
            </form>
          </>
        )}
      </div>
    </div>
  );
};

export default AppointmentBooking;
